 50→    /** @return fragments found on [xml] */
 51→    private fun getFragmentsFromXml(context: Context, @XmlRes xml: Int): List<Fragment> {
 52→        return getAttrFromXml(context, xml, "fragment").map { getInstanceFromClassName(it) }
 53→    }
