 29→object PreferenceTestUtils {
 30→    private fun getAttrFromXml(context: Context, @XmlRes xml: Int, attrName: String, namespace: String = AnkiDroidApp.ANDROID_NAMESPACE): List<String> {
 31→        val occurrences = mutableListOf<String>()
 32→
 33→        val xrp = context.resources.getXml(xml).apply {
 34→            setFeature(XmlPullParser.FEATURE_PROCESS_NAMESPACES, true)
 35→            setFeature(XmlPullParser.FEATURE_REPORT_NAMESPACE_ATTRIBUTES, true)
 36→        }
 37→
 38→        while (xrp.eventType != XmlPullParser.END_DOCUMENT) {
 39→            if (xrp.eventType == XmlPullParser.START_TAG) {
 40→                val attr = xrp.getAttributeValue(namespace, attrName)
 41→                if (attr != null) {
 42→                    occurrences.add(attr)
 43→                }
 44→            }
 45→            xrp.next()
 46→        }
 47→        return occurrences.toList()
 48→    }
 49→
 50→    /** @return fragments found on [xml] */
 51→    private fun getFragmentsFromXml(context: Context, @XmlRes xml: Int): List<Fragment> {
 52→        return getAttrFromXml(context, xml, "fragment").map { getInstanceFromClassName(it) }
 53→    }
 54→
 55→    /** @return recursively fragments found on [xml] and on their children **/
 56→    private fun getFragmentsFromXmlRecursively(context: Context, @XmlRes xml: Int): List<Fragment> {
 57→        val fragments = getFragmentsFromXml(context, xml).toMutableList()
 58→        for (fragment in fragments.filterIsInstance<SettingsFragment>()) {
 59→            fragments.addAll(getFragmentsFromXmlRecursively(context, fragment.preferenceResource))
 60→        }
 61→        return fragments.toList()
 62→    }
 63→
 64→    /** @return [List] of all the distinct preferences fragments **/
 65→    fun getAllPreferencesFragments(context: Context): List<Fragment> {
 66→        val fragments = getFragmentsFromXmlRecursively(context, R.xml.preference_headers) + HeaderFragment()
 67→        return fragments.distinctBy { it::class } // and remove any repeated fragments
 68→    }
 69→
 70→    private fun attrValueToString(value: String, context: Context): String {
 71→        return if (value.startsWith("@")) {
 72→            context.getString(value.substring(1).toInt())
 73→        } else {
 74→            value
 75→        }
 76→    }
 77→
 78→    fun getKeysFromXml(context: Context, @XmlRes xml: Int): List<String> {
 79→        return getAttrFromXml(context, xml, "key").map { attrValueToString(it, context) }
 80→    }
 81→
 82→    fun getAllPreferenceKeys(context: Context): Set<String> {
 83→        return getAllPreferencesFragments(context)
 84→            .filterIsInstance<SettingsFragment>()
 85→            .map { it.preferenceResource }
 86→            .flatMapTo(hashSetOf()) { getKeysFromXml(context, it) }
 87→    }
 88→
 89→    fun getAllCustomButtonKeys(context: Context): Set<String> {
 90→        val ret = AtomicReference<Set<String>>()
 91→        val i = CustomButtonsSettingsFragment.getSubscreenIntent(context)
 92→        ActivityScenario.launch<Preferences>(i).use { scenario ->
 93→            scenario.moveToState(Lifecycle.State.STARTED)
 94→            scenario.onActivity { a: Preferences ->
 95→                val customButtonsFragment = a.supportFragmentManager
 96→                    .findFragmentByTag(CustomButtonsSettingsFragment::class.java.name) as CustomButtonsSettingsFragment
 97→                ret.set(customButtonsFragment.allKeys())
 98→            }
 99→        }
100→        val preferenceKeys = ret.get()?.toMutableSet() ?: throw IllegalStateException("no keys were set")
101→        preferenceKeys.remove("reset_custom_buttons")
102→        return preferenceKeys
103→    }
104→}
